// ── Helper: get questions by category ─────────
export function getByCategory(cat) {
    return cat === "All" ? QUESTIONS : QUESTIONS.filter(q => q.t === cat);
}

// ── Helper: total count ────────────────────────
export const TOTAL = QUESTIONS.length;